import com.amazonaws.auth.{AWSStaticCredentialsProvider, BasicAWSCredentials}
import com.amazonaws.services.s3.AmazonS3ClientBuilder
import com.amazonaws.services.s3.model.S3ObjectSummary

class AwsService {
  private val credentials = new AWSStaticCredentialsProvider(new BasicAWSCredentials("YOUR_ACCESS_KEY", "YOUR_SECRET_KEY"))

  def listObjects(bucketName: String): List[S3ObjectSummary] = {
    val s3Client = AmazonS3ClientBuilder.standard().withCredentials(credentials).build()
    val objects = s3Client.listObjects(bucketName)
    objects.getObjectSummaries.asScala.toList
  }
}